    """Aggregate search results by a metadata field with optional statistics.

    Args:
        search_results: List of SearchResult objects to aggregate
        group_by_field: Metadata field name to group by
        aggregation_funcs: Optional dictionary mapping field_name to aggregation function.
            Example: {"score": max, "count": len}
            If None, defaults to count and average score per group

    Returns:
        Dictionary mapping group_value to aggregated statistics
        Example: {"tech": {"count": 5, "avg_score": 0.85, "max_score": 0.95}}
    """
    groups = defaultdict(lambda: defaultdict(list))

    for result in search_results:
        group_value = result.metadata.get(group_by_field, 'unknown')

        # Always collect scores for default stats
        groups[group_value]['scores'].append(result.score)

        # Collect other fields if they are in aggregation_funcs
        if aggregation_funcs:
            for field_name in aggregation_funcs.keys():
                value = result.metadata.get(field_name)
                groups[group_value][field_name].append(value)

    result_dict = {}

    for group_value in groups:
        stats = {}

        if aggregation_funcs is None:
            # Use default functions on scores
            scores = groups[group_value]['scores']
            stats['count'] = len(scores)
            if scores:
                stats['avg_score'] = sum(scores) / len(scores)
                stats['max_score'] = max(scores)
                stats['min_score'] = min(scores)
            else:
                stats['avg_score'] = 0
                stats['max_score'] = 0
                stats['min_score'] = 0
        else:
            # Use custom functions
            for field_name, func in aggregation_funcs.items():
                values = groups[group_value][field_name]
                filtered_values = [v for v in values if v is not None]
                try:
                    stats[field_name] = func(filtered_values)
                except (ZeroDivisionError, ValueError):
                    stats[field_name] = None

        result_dict[group_value] = stats

    return result_dict

