import json

def build_index_from_json_documents(
    json_file_path: str,
    index_path: str,
    text_field: str = "text",
    metadata_fields: Optional[List[str]] = None,
    backend_name: str = "hnsw"
) -> str:
    """Build a LEANN index from a JSON file containing documents."""

    # Check if JSON file exists
    if not Path(json_file_path).exists():
        raise FileNotFoundError(f"JSON file not found: {json_file_path}")

    # Read and validate JSON content
    try:
        with open(json_file_path, 'r', encoding='utf-8') as f:
            data = json.load(f)
    except json.JSONDecodeError:
        raise ValueError("Invalid JSON file")

    # Validate that data is a list of documents
    if not isinstance(data, list):
        raise ValueError("JSON file must contain a list of documents")

    # Validate that each document has the required text field
    for doc in data:
        if text_field not in doc:
            raise ValueError("missing required field")

    # Prepare texts and metadata for indexing
    texts = []
    metadata_list = []

    for doc in data:
        text = doc[text_field]
        # Extract metadata based on whether metadata_fields is specified
        if metadata_fields is not None:
            metadata = {k: v for k, v in doc.items() if k in metadata_fields}
        else:
            metadata = {k: v for k, v in doc.items() if k != text_field}

        texts.append(text)
        metadata_list.append(metadata)

    # Build the index using LEANN
    builder = LeannBuilder(backend_name=backend_name)
    for text, metadata in zip(texts, metadata_list):
        builder.add_text(text, metadata=metadata)

    builder.build_index(index_path)

    return index_path

