def find_passages_by_text_pattern(
    index_path: str,
    pattern: str,
    case_sensitive: bool = False
) -> List[Dict[str, Any]]:
    """Find all passages in an index whose text contains a specified pattern."""
    if not pattern:
        raise ValueError("pattern cannot be empty")

    meta_path = Path(index_path).parent / f"{Path(index_path).stem}.meta.json"
    if not meta_path.exists():
        raise FileNotFoundError(f"Index metadata file not found at {meta_path}")

    pm = PassageManager(index_path)
    all_passages = pm.get_all()

    matches = []
    for passage in all_passages:
        text = passage.text
        if case_sensitive:
            if pattern in text:
                matches.append(passage)
        else:
            if pattern.lower() in text.lower():
                matches.append(passage)

    return matches

